import React, { useContext, useEffect, useState } from 'react';
import { SafeAreaView, StyleSheet, Text, View, Pressable, TextInput, Alert } from 'react-native';
import { AuthContext } from '../../App';
import { useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { RootStackParamList } from '../navigation/AppNavigator';
import { updateUserProfile } from '../services/firebaseService';
import TopNav from '../components/TopNav';

const ProfileScreen = () => {
  const { profile, signOut, refreshProfile } = useContext(AuthContext);
  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
  const [address, setAddress] = useState('');
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    setAddress(profile?.address ?? '');
  }, [profile]);

  const handleSave = async () => {
    if (!profile) {
      return;
    }
    setSaving(true);
    setMessage('');
    try {
      await updateUserProfile(profile.uid, { address: address.trim() });
      await refreshProfile();
      setMessage('Address saved.');
    } catch (error: any) {
      setMessage(error.message || 'Unable to save your address.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <TopNav />
      <View style={styles.header}>
        <Text style={styles.title}>My profile</Text>
        <Text style={styles.subtitle}>Account details and role information.</Text>
      </View>
      <View style={styles.card}>
        <Text style={styles.label}>Name</Text>
        <Text style={styles.value}>{profile?.name ?? 'Unknown'}</Text>
        <Text style={styles.label}>Phone</Text>
        <Text style={styles.value}>{profile?.phone ?? 'Unknown'}</Text>
        <Text style={styles.label}>Role</Text>
        <Text style={styles.value}>{profile?.role === 'owner' ? 'Owner' : 'Customer'}</Text>
        {profile?.role === 'customer' ? (
          <>
            <Text style={styles.label}>Approval</Text>
            <Text style={styles.value}>{profile.approved ? 'Approved' : 'Pending owner approval'}</Text>
          </>
        ) : null}
        <Text style={styles.label}>Delivery address</Text>
        <TextInput
          style={[styles.input, styles.multiline]}
          value={address}
          onChangeText={setAddress}
          placeholder="Add your delivery address"
          placeholderTextColor="#94A3B8"
          multiline
          numberOfLines={3}
        />
        <Pressable style={styles.saveButton} onPress={handleSave} disabled={saving}>
          <Text style={styles.saveButtonText}>{saving ? 'Saving...' : 'Save address'}</Text>
        </Pressable>
        {message ? <Text style={styles.messageText}>{message}</Text> : null}
      </View>
      <Pressable style={styles.button} onPress={() => navigation.goBack()}>
        <Text style={styles.buttonText}>Back</Text>
      </Pressable>
      <Pressable style={styles.signOutButton} onPress={signOut}>
        <Text style={styles.signOutText}>Sign out</Text>
      </Pressable>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F5FBFF',
    padding: 24
  },
  header: {
    marginBottom: 24
  },
  title: {
    fontSize: 28,
    fontWeight: '800',
    color: '#0F172A',
    marginBottom: 8
  },
  subtitle: {
    fontSize: 15,
    color: '#64748B',
    lineHeight: 22
  },
  card: {
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 24,
    marginBottom: 20,
    boxShadow: '0px 8px 24px rgba(0, 0, 0, 0.10)'
  },
  label: {
    color: '#94A3B8',
    fontSize: 12,
    fontWeight: '700',
    textTransform: 'uppercase',
    marginTop: 18,
    letterSpacing: 0.8
  },
  value: {
    color: '#0F172A',
    fontSize: 18,
    fontWeight: '700',
    marginTop: 8
  },
  input: {
    backgroundColor: '#F8FAFF',
    borderRadius: 16,
    padding: 14,
    borderWidth: 1,
    borderColor: '#E2E8F0',
    color: '#0F172A',
    marginTop: 8
  },
  multiline: {
    minHeight: 90,
    textAlignVertical: 'top'
  },
  saveButton: {
    backgroundColor: '#0EA5E9',
    borderRadius: 14,
    paddingVertical: 14,
    alignItems: 'center',
    marginTop: 16
  },
  saveButtonText: {
    color: 'white',
    fontWeight: '800'
  },
  messageText: {
    marginTop: 12,
    color: '#0F172A',
    fontWeight: '600'
  },
  button: {
    backgroundColor: '#006289',
    borderRadius: 16,
    paddingVertical: 16,
    alignItems: 'center',
    marginBottom: 14
  },
  buttonText: {
    color: 'white',
    fontWeight: '800',
    fontSize: 16
  },
  signOutButton: {
    alignItems: 'center',
    paddingVertical: 16
  },
  signOutText: {
    color: '#DC2626',
    fontWeight: '800',
    fontSize: 16
  }
});

export default ProfileScreen;
